const item = $input.item.json;
const subject = item.subject || '';

// Strip HTML tags from body
const rawBody = item.body?.content || item.bodyPreview || '';
const body = rawBody
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const fullText = subject + '\n' + body;

// 1. 候選人姓名（8 個 pattern）
let candidateName = null;
const SKIP_WORDS = new Set(['通知','安排','確認','面試','邀請','時間','地點','安排']);
const namePatterns = [
  /(?:候選人|應徵者|姓名|求職者)[：:\s]*([^\s，,、。\n<]{2,5})/,
  /Dear\s+(?:Mr\.|Ms\.|Mrs\.)?\s*([A-Z][a-z]{1,10}(?:\s[A-Z][a-z]{1,10})*)/i,
  /親愛的\s*([\u4e00-\u9fa5]{2,5})\s*(?:先生|女士|您好)/,
  /([\u4e00-\u9fa5]{2,4})\s*(?:先生|女士|小姐)\s*您好/,
  /[－\-—]\s*([\u4e00-\u9fa5]{2,4})\s*[－\-—]/,
  /面試[通知排程安排確認]*[：:\s]*([\u4e00-\u9fa5]{2,4})/,
  /^([\u4e00-\u9fa5]{2,4})\s*[-－—\s]*(?:面試|Interview)/im,
  /([A-Z][a-z]{1,15}(?:\s[A-Z][a-z]{1,15})+)\s*(?:面試|Interview)/,
];
for (const p of namePatterns) {
  const m = fullText.match(p);
  if (m) {
    const candidate = m[1].trim();
    if (!SKIP_WORDS.has(candidate) && candidate.length >= 2) {
      candidateName = candidate;
      break;
    }
  }
}

// 2. 面試日期（加入 年月日 格式）
let interviewDate = null;
const datePatterns = [
  { re: /(\d{4})年(\d{1,2})月(\d{1,2})日/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{1,2})月(\d{1,2})日/, fn: m => `${new Date().getFullYear()}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}` },
];
for (const { re, fn } of datePatterns) {
  const m = fullText.match(re);
  if (m) { interviewDate = fn(m); break; }
}

// 3. 面試時間
let interviewTime = null;
const timeMatch = fullText.match(/(?:時間[：:\s]*)?(\d{1,2})[:：](\d{2})/);
if (timeMatch) {
  let h = parseInt(timeMatch[1]);
  const context = fullText.substring(Math.max(0, fullText.indexOf(timeMatch[0])-10), fullText.indexOf(timeMatch[0])+20);
  if (/下午|PM|pm/.test(context) && h < 12) h += 12;
  interviewTime = `${String(h).padStart(2,'0')}:${timeMatch[2]}`;
}

// 4. 輪次
let round = 1;
if (/複試|二試|second\s*round|第二輪/i.test(fullText)) round = 2;
if (/三試|third\s*round|第三輪/i.test(fullText)) round = 3;
if (/終試|final\s*round|最終面試/i.test(fullText)) round = 4;

// 5. 應徵職位
let appliedPosition = '未知職位';
const posMatch = fullText.match(/(?:應徵[職\s]*位[置]?|職位|Position|職缺)[：:\s]*([^\n，,。<]{2,20})/i);
if (posMatch) appliedPosition = posMatch[1].trim();

// 6. 部門
let department = '未分類';
const deptMap = [
  [/軟體|software/i, '軟體部'],
  [/RF|射頻/i, '耕興'],
  [/SAR|比吸率/i, '耕興'],
  [/財務|finance|會計/i, '財務部'],
  [/行政|admin/i, '行政部'],
  [/安規|regulatory/i, '安規部'],
  [/業務|sales/i, '業務部'],
  [/人資|人事/i, '人資部'],
];
for (const [re, dept] of deptMap) {
  if (re.test(fullText)) { department = dept; break; }
}

// 7. 負責 HR
const hrNames = ['李沛晴', '陳清彥', '黃友為', 'Peggy', 'Yen', 'Evan'];
let hrOwner = null;
for (const name of hrNames) {
  if (fullText.includes(name)) { hrOwner = name; break; }
}
if (!hrOwner && item.from?.emailAddress?.name) {
  hrOwner = item.from.emailAddress.name;
}

// 8. 地點
let location = null;
const locMatch = fullText.match(/(?:地點|Location|地址|會議室|面試地點|請至)[：:　 ]*([^\n，,<]{2,30})/);
if (locMatch) location = locMatch[1].trim();

// 9. 只有姓名找不到才需要 AI（日期缺失不算）
const needsAI = !candidateName;

return {
  email_msg_id: item.id,
  email_subject: subject,
  email_web_link: item.webLink,
  sender: item.from?.emailAddress?.address,
  received_at: item.receivedDateTime,
  candidate_name: candidateName,
  applied_position: appliedPosition,
  department: department,
  interview_date: interviewDate,
  interview_time: interviewTime,
  round: round,
  location: location,
  hr_owner: hrOwner,
  needs_ai: needsAI,
  body_text: body.substring(0, 3000),
};

// 非面試關鍵字 → 略過
const item = $input.item.json;
return {
  email_msg_id: item.id,
  email_subject: item.subject,
  sender: item.from?.emailAddress?.address,
  received_at: item.receivedDateTime,
  action: 'skipped',
  error_msg: '非面試類信件，歷史匯入略過',
};

// 合併 Regex + AI 結果（HTTP Request 版）
const base = $('Code：Regex 解析面試資料').item.json;
let aiResult = {};
try {
  const inputJson = $input.item.json;
  // HTTP Request response: content is array [{type:'text',text:'...'}]
  let raw = '';
  if (Array.isArray(inputJson.content)) {
    raw = inputJson.content[0]?.text || '';
  } else {
    raw = inputJson.content || inputJson.text || '';
  }
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) aiResult = JSON.parse(match[0]);
} catch(e) {}

return {
  email_msg_id: base.email_msg_id,
  email_subject: base.email_subject,
  email_web_link: base.email_web_link,
  sender: base.sender,
  received_at: base.received_at,
  candidate_name: base.candidate_name || aiResult.candidate_name || '未知姓名',
  applied_position: base.applied_position !== '未知職位' ? base.applied_position : (aiResult.applied_position || '未知職位'),
  department: base.department !== '未分類' ? base.department : (aiResult.department || '未分類'),
  interview_date: base.interview_date || aiResult.interview_date,
  interview_time: base.interview_time || aiResult.interview_time,
  round: base.round || aiResult.round || 1,
  location: base.location || aiResult.location,
  hr_owner: base.hr_owner || aiResult.hr_owner,
  parse_method: 'regex+ai',
};
